# -*- coding: utf-8 -*-
"""
Favicon + 18 subpages (Ayushman, PMAY, Mudra).
Appends to subpages_data.py (keeps PM Kisan), adds favicon, rebuilds.
Run: python batch_a.py
"""
import os, sys

REPO = os.path.dirname(os.path.abspath(__file__))
def read(f):
    with open(os.path.join(REPO, f), "r", encoding="utf-8") as fh: return fh.read()
def write(f, c):
    with open(os.path.join(REPO, f), "w", encoding="utf-8") as fh: fh.write(c)

# ═══════════ FAVICON ═══════════
print("1. Favicon ...")
FAVICON = '''<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64">
<defs><linearGradient id="g" x1="0" y1="0" x2="0" y2="1">
<stop offset="0" stop-color="#F59E1B"/><stop offset="1" stop-color="#E4590A"/></linearGradient></defs>
<rect width="64" height="64" rx="13" fill="url(#g)"/>
<text x="32" y="45" font-family="Arial,sans-serif" font-size="42" font-weight="bold" fill="#fff" text-anchor="middle">&#8377;</text>
</svg>'''
write("favicon.svg", FAVICON)

gen = read("generate.py")
if "favicon.svg" not in gen:
    marker = '<link rel="canonical" href="%s">'
    gen = gen.replace(marker, marker + '<link rel="icon" type="image/svg+xml" href="/favicon.svg">', 1)
    # add to build output
    gen = gen.replace('w("ads.txt"',
        'w("favicon.svg", open(os.path.join(OUT,"favicon.svg"),encoding="utf-8").read())\n    w("ads.txt"', 1)
    write("generate.py", gen)
    print("  Favicon added to head + build")
else:
    print("  Favicon already present")

# ═══════════ SUBPAGES DATA ═══════════
print("\n2. Adding 18 subpages (Ayushman, PMAY, Mudra) ...")

